namespace sv_48588d019b60411e8f73c0fad731854c.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 25),
            new(2, "Margherita Pizza", "Simple pizza with tomato sauce, fresh mozzarella, and basil.", 45),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 35),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato-cream sauce.", 40),
            new(5, "Palak Paneer", "Fresh spinach cooked with cubes of paneer cheese and aromatic spices.", 30),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Spit-roasted pork with pineapple, cilantro, and onion on corn tortillas.", 50),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken, covered in tangy green salsa.", 35),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_48588d019b60411e8f73c0fad731854c.Services
@using Microsoft.AspNetCore.Components
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _error;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();
            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload if the cuisine actually changed
        if (CuisineId == _loadedCuisineId && _recipes is not null)
            return;

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            // Check cancellation after await in case a newer request superseded this one
            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Superseded by a newer request — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _isRefreshing = false;
            _error = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

